mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd, FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm, info.DISTRIBUTE_TYPE_CD AS distributeTypeCd, FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm, info.VIDEO_NO AS videoNo, info.VIDEO_NM AS videoNm, info.REV_NO AS revNo, info.CURRENT_PAGE_NO AS currentPageNo, info.TOTAL_PAGE_NO AS totalPageNo, info.INSERT_UID AS insertUid, info.OBJECT_ID AS objectId, info.INSERT_USER_NM AS insertUserNm, updateUser.USER_NM AS updateUserNm, info.INSERT_DEPT_NM AS insertDeptNm, info.STD_GAPP_DT AS stdGappDt, info.CHANGE_GAPP_DT AS changeGappDt, info.ECN_NO AS ecnNo, ecnInsert.USER_NM AS ecnUserNm, company.COMPANY_NM AS companyNm, purchaser.USER_NM AS purchaserUserNm, info.PURCHASER_UID AS purchaserUid, info.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm, info.PROTECT_YN AS protectYn, info.PROTECT_YN AS protectYnView, info.UPDATE_DT AS updateDt, info.INSERT_DT AS insertDt, info.INTERFACE_DT AS interfaceDt, company.COMPANY_CD AS companyCd, info.PRODUCT_CD AS productCd, COALESCE(info.PRODUCT_CD, '') AS productNm, 1 AS fileNo, info.FILE_NM AS fileNm, info.FILE_PATH_NM AS filePath, info.ORG_FILE_NM AS fileViewNm, info.ORG_FILE_NM AS orgFileNm, info.FILE_SIZE AS fileSize, info.ECN_TITLE AS ecnTitle, info.ECN_VENDOR_USER AS ecnVendorUser, info.VALID_TYPE AS validType, '' AS checkSum FROM DOCS_VIDEO info LEFT JOIN DOCS_USER insertUser ON info.INSERT_UID = insertUser.USER_ID LEFT JOIN DOCS_USER updateUser ON info.UPDATE_UID = updateUser.USER_ID LEFT JOIN DOCS_COMPANY company ON company.BIZ_NO = info.VENDOR_CD LEFT JOIN DOCS_USER purchaser ON purchaser.USER_ID = info.PURCHASER_UID LEFT JOIN DOCS_USER ecnInsert ON ecnInsert.USER_ID = info.ecn_insert_uid WHERE 1=1 -- 조건절들
AND info.BUSINESS_TYPE_CD = #{businessTypeCd}
AND info.BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND info.VIDEO_NO = UPPER(TRIM(#{videoNo}))
AND info.VIDEO_NO LIKE '%' || UPPER(TRIM(#{videoNo})) || '%'
-- 기타 조건들 생략
ORDER BY info.INSERT_DT DESC, info.CURRENT_PAGE_NO
ORDER BY ${sortColumn} ${order}
) A1 ) B1 WHERE 1=1
AND B1.PAGEINDEX <= #{end}
AND B1.PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd , FN_GET_CD_NM('businessTypeCd', info.BUSINESS_TYPE_CD, 'ko') AS businessTypeNm , info.DISTRIBUTE_TYPE_CD AS distributeTypeCd , FN_GET_CD_NM('distributeTypeCd', info.DISTRIBUTE_TYPE_CD, 'ko') AS distributeTypeNm , info.VIDEO_NO AS videoNo , info.VIDEO_NM AS videoNm , info.REV_NO AS revNo , info.CURRENT_PAGE_NO AS currentPageNo , info.TOTAL_PAGE_NO AS totalPageNo , info.INSERT_UID AS insertUid , info.OBJECT_ID AS objectId , insertUser.USER_NM AS insertUserNm , updateUser.USER_NM AS updateUserNm , info.INSERT_DEPT_NM AS insertDeptNm , info.STD_GAPP_DT AS stdGappDt , info.CHANGE_GAPP_DT AS changeGappDt , info.ECN_NO AS ecnNo , ecnInsert.USER_NM AS ecnUserNm , company.COMPANY_NM AS companyNm , purchaser.USER_NM AS purchaserUserNm , info.PURCHASER_UID AS purchaserUid , info.BUSINESS_AREA_CD AS businessAreaCd , FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm , info.PROTECT_YN AS protectYn , info.PROTECT_YN AS protectYnView , info.UPDATE_DT AS updateDt , info.INSERT_DT AS insertDt , info.INTERFACE_DT AS interfaceDt , company.COMPANY_CD AS companyCd , info.PRODUCT_CD AS productCd , COALESCE(info.PRODUCT_CD, '') AS productNm , 1 AS fileNo , info.FILE_NM AS fileNm , info.FILE_PATH_NM AS filePath , info.ORG_FILE_NM AS fileViewNm , info.ORG_FILE_NM AS orgFileNm , info.FILE_SIZE AS fileSize , info.ECN_TITLE AS ecnTitle , info.ECN_VENDOR_USER AS ecnVendorUser , info.VALID_TYPE AS validType , '' AS checkSum FROM DOCS_VIDEO info LEFT JOIN DOCS_USER insertUser ON info.INSERT_UID = insertUser.USER_ID LEFT JOIN DOCS_USER updateUser ON info.UPDATE_UID = updateUser.USER_ID LEFT JOIN DOCS_COMPANY company ON company.BIZ_NO = info.VENDOR_CD LEFT JOIN DOCS_USER purchaser ON purchaser.USER_ID = info.PURCHASER_UID LEFT JOIN DOCS_USER ecnInsert ON ecnInsert.USER_ID = info.ecn_insert_uid WHERE 1=1
AND info.BUSINESS_TYPE_CD = #{businessTypeCd}
AND info.BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND info.VIDEO_NO = UPPER(TRIM(#{videoNo}))
AND info.VIDEO_NO LIKE '%' || UPPER(TRIM(#{videoNo})) || '%'
AND info.VIDEO_NM LIKE '%' || #{videoNm} || '%'
AND info.PURCHASER_UID = #{purchaserUid}
AND info.DISTRIBUTE_TYPE_CD = #{distributeTypeCd}
AND info.ECN_NO LIKE '%' || UPPER(TRIM(#{ecnNo})) || '%'
AND company.COMPANY_CD = #{companyCd}
AND info.PRODUCT_CD = #{productCd}
AND info.INSERT_UID = #{insertUid}
AND info.VALID_TYPE IS NULL
AND info.VALID_TYPE = 'N'
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
AND LPAD(info.REV_NO, 2, '0') = ( SELECT MAX(LPAD(sub_info.REV_NO, 2, '0')) FROM DOCS_VIDEO sub_info WHERE sub_info.VIDEO_NO = info.VIDEO_NO AND sub_info.CURRENT_PAGE_NO = info.CURRENT_PAGE_NO )
AND (
(info.VIDEO_NO LIKE '%' || UPPER(TRIM(#{videoInfo.videoNo})) || '%')
)
AND (
(info.VIDEO_NO = UPPER(TRIM(#{videoInfo.videoNo})))
)
) A1 ) B1

SELECT OBJECT_ID
FROM DOCS_VIDEO
WHERE OBJECT_ID = #{objectId}

SELECT FILE_PATH_NM
FROM DOCS_VIDEO
WHERE OBJECT_ID = #{objectId}
